import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for p in fw['topLevelPackages']:
                pkgs[(name, p['id'])] = p['resolvedVersion']
    return pkgs

b = extract(baseline)
a = extract(after)
changes = []
for k in sorted(set(b) | set(a)):
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        changes.append((k[0], k[1], bv, av))
    else:
        print(f'UNCHANGED: {k[0]:15s} {k[1]:50s} {bv}')
if changes:
    for c in changes:
        print(f'CHANGED:   {c[0]:15s} {c[1]:50s} {c[2]} -> {c[3]}')
else:
    print('ALL PACKAGES MATCH - conversion is version-neutral')
"

